def catalan(n, memo={0: 1, 1: 1}):
    if n in memo: return memo[n]
    res = 0
    for i in range(n):
        res += catalan(i, memo) * catalan(n - 1 - i, memo)
    memo[n] = res
    return res

if __name__ == "__main__":
    print(f"5th Catalan: {catalan(4)}") # Note: C(4) is 14
